const churned = $('Fetch Churned Users').first().json;
const accuracy = $('Fetch 7-Day Accuracy').first().json;

const users = Array.isArray(churned) ? churned : (churned.users || []);

if (users.length === 0) {
  return [{ json: { skip: true, message: 'No churned users to win back today' } }];
}

return users.map(user => ({
  json: {
    skip: false,
    userId: user.telegram_id || user.chat_id || user.id,
    username: user.username || user.first_name || 'there',
    daysSinceChurn: user.days_since_churn || user.days_inactive || 3,
    previousPlan: user.previous_plan || user.last_plan || 'Premium',
    totalPredictions: user.total_predictions || user.prediction_count || 0,
    missedSignals: user.missed_signals || 0,
    accuracy: JSON.stringify(accuracy)
  }
}));

const response = $input.first().json;
let text = '';

if (response.content && response.content.length > 0) {
  text = response.content[0].text;
} else {
  text = '<b>We\'ve missed you at BTC Seer</b>\n\nOur AI has been making some strong calls while you were away. Come see what you missed — tap /premium to reactivate.';
}

return [{ json: { text, userId: $('Build Claude Prompt').first().json.userId } }];

const result = $input.first().json;
const userId = $('Extract Message Text').first().json.userId;
const success = result.ok === true;

console.log(`[Win-Back] Sent to user ${userId}: ${success ? 'OK' : 'FAILED'}`);

return [{ json: { userId, success, timestamp: new Date().toISOString() } }];
